UPDATE public.questions SET
  stimulus_text = 'Many people associate the word "tradition" with something that is unchanging.  However, traditions are actually dynamic and evolve over time. One of the most obvious examples is the evolution of the American Thanksgiving meal. The traditional Thanksgiving meal in the early 19th century featured mostly roast turkey, potatoes, and cranberries. However, the Thanksgiving meal today often includes dishes such as stuffing, sweet potatoes, cornbread, and pumpkin pie.  These additions and changes demonstrate that the Thanksgiving meal continues to evolve and grow.  What is the main idea of this passage?',
  question_text = 'The main idea of the passage is that',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"the American Thanksgiving meal is no longer traditional.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"the Thanksgiving meal has been evolving for centuries.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"the Thanksgiving meal is a constantly changing tradition.","is_correct":true,"explanation":"The passage states that traditions are dynamic and evolve over time, and it uses the Thanksgiving meal as an example of this.  The passage describes how the Thanksgiving meal has changed from the early 19th century to today, indicating that the Thanksgiving meal is a constantly changing tradition. Choice C matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"the Thanksgiving meal is a reflection of American history and culture.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'C',
  explanation = 'The passage states that traditions are dynamic and evolve over time, and it uses the Thanksgiving meal as an example of this.  The passage describes how the Thanksgiving meal has changed from the early 19th century to today, indicating that the Thanksgiving meal is a constantly changing tradition. The passage states that "Many people associate the word "tradition" with something that is unchanging. However, traditions are actually dynamic a…", which is the textual anchor for eliminating weaker choices. Choice C is correct because it aligns with that evidence: the Thanksgiving meal is a constantly changing tradition.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"CID","domain_id":"information","opensat_index":672,"opensat_domain":"Information and Ideas","opensat_raw_id":"random_id_e9","opensat_difficulty":"Hard","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.898Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
