UPDATE public.questions SET
  stimulus_text = 'The first paragraph of the passage begins by describing a traditional, or customary, way of using materials to create clothing. But then it transitions to an observation about a change that has occurred within the recent past. How does the text indicate that the change is recent? Taken together, these details imply a broader principle that extends beyond the immediate example, though the author stops short of claiming universal proof. Readers must weigh both the evidence presented and the limits the author acknowledges.',
