UPDATE public.questions SET
  stimulus_text = 'In the 1960s, a group of scientists in the United States developed a new method for producing aluminum, but it was not clear what the environmental implications of the method were. Some scientists worried that the new method would release toxic chemicals into the environment, while others believed that the method would be safer than the previous methods. The new method was eventually adopted by the aluminum industry, and its environmental effects have been studied extensively since then. Based on the passage, which of the following claims is best supported by the text?',
  question_text = 'Which of the following claims is best supported by the text?',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"Scientists had no concerns about the environmental effects of the new method for producing aluminum.","is_correct":false,"explanation":"Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"The environmental effects of the new method for producing aluminum were clear from the start.","is_correct":false,"explanation":"Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"The environmental effects of the new method for producing aluminum were studied extensively before the method was adopted by the aluminum industry.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"The environmental effects of the new method for producing aluminum were not fully understood until after the method was adopted by the aluminum industry.","is_correct":true,"explanation":"Choice D matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'D',
  explanation = 'The passage states that it was not clear what the environmental implications of the new method were. This suggests that the environmental effects of the new method were not fully understood until after the method was adopted by the aluminum industry. The passage also states that the environmental effects have been studied extensively since then, which further supports the idea that the environmental effects were not fully understood until after the method was adopted. The passage states that "In the 1960s, a group of scientists in the United States developed a new method for producing aluminum, but it was not c…", which is the textual anchor for eliminating weaker choices. Choice D is correct because it aligns with that evidence: The environmental effects of the new method for producing aluminum were not fully understood until a…. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
