UPDATE public.questions SET
  stimulus_text = 'In 1971, after working as a journalist for several years, the writer Maya Angelou published her first volume of poetry, "And Still I Rise." The book, which contains a collection of poems that explore themes of resilience, hope, and the African American experience, became a bestseller. Angelou continued to publish works throughout the 1970s and 1980s, eventually becoming an iconic figure in American literature.',
