UPDATE public.questions SET
  stimulus_text = 'The passage below is from a 1980 book about the history of the early American republic. The author is explaining why, in her view, the concept of the "self-made man" is an important idea to consider when studying the development of the United States.\
\"There is a tendency to regard the self-made man as a kind of American hero. But the self-made man, though he is the product of his own efforts, is also the product of the conditions that made his success possible. The self-made man is not a creation ex nihilo. He is, rather, a product of his time and place.\"',
  question_text = 'Which choice best describes the central idea of the passage?',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"The self-made man is an American hero, and his success is due to his own efforts.","is_correct":false,"explanation":"Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"The self-made man is not a creation ex nihilo, but rather a product of his time and place.","is_correct":true,"explanation":"Choice B matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"The self-made man is not a product of his own efforts, but rather a product of the conditions that made his success possible.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"The self-made man is a creation ex nihilo, and he is not a product of his time and place.","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'B',
  explanation = 'The author argues that the self-made man is not a creation ex nihilo, which means that he was not created from nothing. Instead, the self-made man is a product of his time and place. The author is arguing that the self-made man is not simply a product of his own efforts, but he is also shaped by the conditions of his time and place. The passage states that "The passage below is from a 1980 book about the history of the early American republic. The author is explaining why, in…", which is the textual anchor for eliminating weaker choices. Choice B is correct because it aligns with that evidence: The self-made man is not a creation ex nihilo, but rather a product of his time and place.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"CID","domain_id":"information","opensat_index":1078,"opensat_domain":"Information and Ideas","opensat_raw_id":"94440b84","opensat_difficulty":"Hard","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.898Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
