UPDATE public.questions SET
  stimulus_text = 'In 1916, H. Dugdale Sykes disputed claims that *The Two Noble Kinsmen* was coauthored by William Shakespeare and John Fletcher. Sykes felt Fletcher’s contributions to the play were obvious—Fletcher had a distinct style in his other plays, so much so that lines with that style were considered sufficient evidence of Fletcher’s authorship. But for the lines not deemed to be by Fletcher, Sykes felt that their depiction of women indicated that their author was not Shakespeare but Philip Massinger.',
  question_text = 'According to the passage, what is Sykes''s primary argument?',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"That *The Two Noble Kinsmen* is entirely written by John Fletcher.","is_correct":false,"explanation":"Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"That Shakespeare did not contribute to *The Two Noble Kinsmen* at all.","is_correct":false,"explanation":"Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"That Philip Massinger was the main author of *The Two Noble Kinsmen*.","is_correct":true,"explanation":"Choice C matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"That *The Two Noble Kinsmen* is a collaborative work between Shakespeare and Fletcher, but Fletcher wrote more of the play than Shakespeare.","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'C',
  explanation = 'The passage states that Sykes felt that the depiction of women in *The Two Noble Kinsmen* indicated that the author was not Shakespeare, but Philip Massinger. This supports the claim that Sykes''s primary argument is that Massinger was the main author of the play. The passage states that "In 1916, H. Dugdale Sykes disputed claims that *The Two Noble Kinsmen* was coauthored by William Shakespeare and John Fl…", which is the textual anchor for eliminating weaker choices. Choice C is correct because it aligns with that evidence: That Philip Massinger was the main author of *The Two Noble Kinsmen*.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
