UPDATE public.questions SET
  stimulus_text = 'The author of the essay, a scholar of ancient Greek poetry, argues that Sappho’s poetry is a form of "direct address" because she often writes as if she is speaking directly to a person, even though the reader is not present. This technique, she argues, is one way that Sappho conveys her powerful emotions. For example, in one particularly moving poem, Sappho writes, "I wish I could say to you—that I could say—that what I wish, that what I desire, that what I’m longing for, that what I’m searching for, that what is in my soul, could all come to pass. You would never leave me, never forget me." However, in another poem, the poet uses a less personal, more introspective tone. "My mind is at war, and my whole body is in a fever," she writes, "because I long for you, but you, you are not here."  The author would most likely agree that this change in tone is intended to _____.',
  question_text = 'Which choice best completes the sentence?',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"create a sense of mystery and intrigue.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"highlight the speaker’s complicated feelings.","is_correct":true,"explanation":"The second poem uses a less personal, more introspective tone to highlight the speaker’s complicated feelings, which is one of the main arguments the author makes. Choice B matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"emphasize the speaker’s longing for the reader.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"reinforce the speaker’s desire to be understood.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'B',
  explanation = 'The second poem uses a less personal, more introspective tone to highlight the speaker’s complicated feelings, which is one of the main arguments the author makes. The passage states that "The author of the essay, a scholar of ancient Greek poetry, argues that Sappho’s poetry is a form of "direct address" be…", which is the textual anchor for eliminating weaker choices. Choice B is correct because it aligns with that evidence: highlight the speaker’s complicated feelings.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
