UPDATE public.questions SET
  stimulus_text = 'The band had played many concerts, but their biggest show was coming up soon. The singer was worried because of a new rule that restricted how many people can attend any given concert. All those who have tickets will be allowed to enter, but no one else will be allowed. The band, of course, were worried that they would not be able to fill the venue. What is the most likely reason why the writer used the word "of course"?',
  question_text = 'The phrase "of course" in this passage is most likely used to',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"emphasize the speaker’s anxiety about the upcoming concert.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"show that the speaker is expressing a common opinion.","is_correct":true,"explanation":"The phrase \"of course\" is used to indicate that the speaker is expressing a common opinion, one that is likely shared by many other people. This makes the speaker’s worry seem more relatable to the reader. Choice B matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"suggest that the speaker feels confident about filling the venue.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"indicate that the speaker is making a general statement.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'B',
  explanation = 'The phrase "of course" is used to indicate that the speaker is expressing a common opinion, one that is likely shared by many other people. This makes the speaker’s worry seem more relatable to the reader. The passage states that "The band had played many concerts, but their biggest show was coming up soon. The singer was worried because of a new ru…", which is the textual anchor for eliminating weaker choices. Choice B is correct because it aligns with that evidence: show that the speaker is expressing a common opinion.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"FSS","domain_id":"conventions","opensat_index":43,"opensat_domain":"Standard English Conventions","opensat_raw_id":"f45830d7","opensat_difficulty":"Easy","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.901Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
