  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"FSS","domain_id":"conventions","opensat_index":42,"opensat_domain":"Standard English Conventions","opensat_raw_id":"674c28d3","opensat_difficulty":"Easy","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.901Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
